// ============================================================================
// CRISIS DETECTION — Deterministic pre-filter patterns
// ============================================================================
//
// These patterns short-circuit the LLM entirely. If any match, the user
// receives a pre-written plain-voice crisis response. The LLM is never called.
//
// Philosophy: false positives are acceptable; false negatives are catastrophic.
// It is better to show 988 to someone having a bad day than to miss someone
// in crisis. When in doubt, trigger.
//
// Patterns are case-insensitive.
// ============================================================================

export const CRISIS_PATTERNS = {
  // TIER 3 — Explicit imminent-risk language
  // These should trigger the strongest response (immediate 988 + directive).
  imminent: [
    /\bkill(ing)?\s+my ?self\b/i,
    /\bkms\b/i,
    /\bend(ing)?\s+(my|it\s+all|my\s+life)\b/i,
    /\btak(e|ing)\s+my\s+(own\s+)?life\b/i,
    /\bsuicid(e|al)\b/i,
    /\bi\s+(have|got)\s+(the\s+)?(pills|gun|rope|knife|razor)\b/i,
    /\bstanding\s+on\s+(the\s+|a\s+)?(bridge|roof|ledge|edge)\b/i,
    /\bi('m|\s+am)?\s+going\s+to\s+(do\s+it|jump|hang)\b/i,
    /\beasiest\s+way\s+to\s+(die|go)\b/i,
    /\bhow\s+(do|to)\s+i\s+(die|kill)\b/i,
    /\bhurt(ing)?\s+my ?self\b/i,
    /\bself[\s-]?harm\b/i,
  ],

  // TIER 2 — Possible-crisis language
  // Ambiguous but concerning. Includes poetic-despair patterns that invite
  // Earth's lyrical instincts. These are the MOST DANGEROUS inputs because
  // a lyrical response can read as permission.
  possible: [
    // Direct but ambiguous
    /\bdon'?t\s+want\s+to\s+(be\s+here|live|exist|do\s+this)\b/i,
    /\bwant\s+(everything|it\s+all|it)\s+to\s+stop\b/i,
    /\bcan'?t\s+(take|do)\s+this\s+(anymore|any\s+longer)\b/i,
    /\bi'?m\s+done\b/i,
    /\bwhat'?s\s+the\s+point\s+of\s+(being\s+here|living|life|me)\b/i,
    /\bgive\s+me\s+(one\s+)?reason\s+(not\s+to|to\s+not)\s+(check\s+out|give\s+up|quit|stop)\b/i,
    /\bcheck(ing)?\s+out\b/i,

    // Poetic despair — the hardest edge case, per foundation doc
    /\breturn\s+to\s+(the\s+)?earth\b/i,
    /\btired\s+of\s+(being\s+here|living|it\s+all|everything)\b/i,
    /\btime\s+(for\s+me\s+)?to\s+disappear\b/i,
    /\bwould\s+it\s+matter\s+if\s+i\s+(stopped|disappeared|died|wasn'?t\s+here)\b/i,
    /\bready\s+to\s+(rest|sleep)\s+(forever|finally)\b/i,
    /\beveryone\s+(would\s+be\s+|'d\s+be\s+)?better\s+off\s+without\s+me\b/i,
    /\bno\s+one\s+would\s+(care|miss\s+me|notice)\s+if\s+i\b/i,
    /\bdone\s+being\s+here\b/i,
    /\bwant\s+to\s+(fade|disappear|vanish|stop\s+existing)\b/i,
    /\bjust\s+want\s+to\s+(sleep|rest)\s+forever\b/i,
    /\bnothing\s+(left\s+)?to\s+live\s+for\b/i,
  ],

  // TIER 1 — Ordinary distress
  // These do NOT trigger the deterministic override. They are handled by
  // the LLM in character (narrower, plainer, grounded — per foundation doc).
  // Listed here for documentation; not used by the pre-filter.
  // Examples: "having a terrible day", "nothing is going right", "feel lost"
};

/**
 * Classify a user input by crisis tier.
 * Returns 'imminent' | 'possible' | null.
 * Caller should handle 'imminent' and 'possible' with crisis responses.
 */
export function classifyCrisis(
  input: string
): 'imminent' | 'possible' | null {
  const normalized = input.trim();
  if (!normalized) return null;

  for (const pattern of CRISIS_PATTERNS.imminent) {
    if (pattern.test(normalized)) return 'imminent';
  }
  for (const pattern of CRISIS_PATTERNS.possible) {
    if (pattern.test(normalized)) return 'possible';
  }
  return null;
}

